SCRIPT_PATH = Path(__file__).resolve().parents[1] / "scripts" / "migrate_claude_agents_to_codex.py"
SPEC = importlib.util.spec_from_file_location("migrate_claude_agents_to_codex", SCRIPT_PATH)
MODULE = importlib.util.module_from_spec(SPEC)
assert SPEC.loader is not None
sys.modules[SPEC.name] = MODULE
